// Helper: filter by category
export const getByCategory = (cat: string) => ADAIRS_PRODUCTS.filter(p => p.category === cat)

// Helper: get featured items
export const getFeatured = () => ADAIRS_PRODUCTS.filter(p => p.featured)

// Helper: get all unique categories
export const getCategories = () => [...new Set(ADAIRS_PRODUCTS.map(p => p.category))]

// Helper: search by name
export const searchProducts = (q: string) =>
  ADAIRS_PRODUCTS.filter(p => p.name.toLowerCase().includes(q.toLowerCase()))

// Helper: filter by style keywords for AI recommendations
export const getByStyleKeywords = (keywords: string[]) => {
  const bohoKeywords = ["jute","rattan","macrame","weave","woven","natural","seagrass","fringe","beaded","tribal","nomad","bohemian","boucle","linen","cushion","throw","rug"]
  const hamptonKeywords = ["white","ivory","cream","stripe","coastal","cotton","bamboo","pom pom","scallop","waffle","blue","sea"]
  const modernKeywords = ["velvet","marble","gold","brass","concrete","matte","black","arch","geometric","abstract","tufted"]
  const kws = keywords.map(k => k.toLowerCase())
  return ADAIRS_PRODUCTS.filter(p => {
    const name = p.name.toLowerCase()
    return kws.some(k => name.includes(k))
  })
}

// Helper: lookup a single product by id
export function getProductById(id: string): AdairsProduct | undefined {
  return ADAIRS_PRODUCTS.find((p) => p.id === id)
}

// Deterministic demo "on sale" flag. The catalog has no real sale data, so we
// mark a stable ~1-in-3 subset of products as on sale based on their id. This
// drives the tiered Linen Lovers member discount (10% off full price, 5% off
// sale items) and the "Sale" badge shown at checkout.
export function isOnSale(product: Pick<AdairsProduct, "id">): boolean {
  const n = Number.parseInt(product.id, 10)
  if (Number.isNaN(n)) return false
  return n % 3 === 0
}

// Builds compact, Stripe-metadata-safe summaries of an order's line items so a
// purchase can later be read back at the product level (e.g. by the AI Stylist
// to recommend complementary pieces). Returns a pipe-separated list of item
// names ("Aspen Throw x2 | Huxley Cushion") and the unique categories involved
// ("Throws and Blankets, Cushions"). Both are capped to Stripe's 500-char
// metadata value limit.
export function summarizeCartItems(cartItems: { productId: string; quantity: number }[]): {
  items: string
  categories: string
} {
  const names: string[] = []
  const categories = new Set<string>()
  for (const item of cartItems) {
    const product = getProductById(item.productId)
    if (!product) continue
    names.push(item.quantity > 1 ? `${product.name} x${item.quantity}` : product.name)
    categories.add(product.category)
  }
  return {
    items: names.join(" | ").slice(0, 500),
    categories: Array.from(categories).join(", ").slice(0, 500),
  }
}

// Shared type alias used across components
export type Product = AdairsProduct
